#include <iostream>
#include <cmath>
#include <iomanip>

struct Point {
    int x;
    int y;
};

double distance(Point p1, Point p2);

int main() {
    std::cout << std::fixed << std::setprecision(6);
    Point p1 = {0, 0};
    Point p2 = {3, 4};
    std::cout << distance(p1, p2) << std::endl;

    Point p3 = {1, 1};
    Point p4 = {1, 1};
    std::cout << distance(p3, p4) << std::endl;

    Point p5 = {-1, -1};
    Point p6 = {2, 3};
    std::cout << distance(p5, p6) << std::endl;

    return 0;
}
